import{_ as a,o as e,c as i,ag as t}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"开发文档","description":"","frontmatter":{},"headers":[{"level":1,"title":"开发文档","slug":"开发文档","link":"#开发文档","children":[{"level":2,"title":"目录简介","slug":"目录简介","link":"#目录简介","children":[]},{"level":2,"title":"项目列表","slug":"项目列表","link":"#项目列表","children":[{"level":3,"title":"CAS 单点登录系统","slug":"cas-单点登录系统","link":"#cas-单点登录系统","children":[]},{"level":3,"title":"智能中间件集成验证脚手架","slug":"智能中间件集成验证脚手架","link":"#智能中间件集成验证脚手架","children":[]}]},{"level":2,"title":"技术支持","slug":"技术支持","link":"#技术支持","children":[]},{"level":2,"title":"未来规划","slug":"未来规划","link":"#未来规划","children":[]}]}],"relativePath":"dev/index.md","filePath":"dev/index.md"}'),r={name:"dev/index.md"};function o(n,l,s,h,c,d){return e(),i("div",null,[...l[0]||(l[0]=[t('<h1 id="开发文档" tabindex="-1">开发文档 <a class="header-anchor" href="#开发文档" aria-label="Permalink to &quot;开发文档&quot;">​</a></h1><h2 id="目录简介" tabindex="-1">目录简介 <a class="header-anchor" href="#目录简介" aria-label="Permalink to &quot;目录简介&quot;">​</a></h2><p>本目录包含北京必码科技工作室提供的开发相关文档和项目，旨在帮助开发者快速上手和使用我们的技术解决方案。</p><h2 id="项目列表" tabindex="-1">项目列表 <a class="header-anchor" href="#项目列表" aria-label="Permalink to &quot;项目列表&quot;">​</a></h2><h3 id="cas-单点登录系统" tabindex="-1">CAS 单点登录系统 <a class="header-anchor" href="#cas-单点登录系统" aria-label="Permalink to &quot;CAS 单点登录系统&quot;">​</a></h3><p>CAS (Central Authentication Service) 是 Apereo 基金会维护的企业级开源单点登录系统，为企业应用提供统一的身份认证与授权机制。我们基于不同版本的 CAS Overlay 进行了定制化开发，提供了完整的开发基座、配置模板和部署方案。</p><p><strong>主要特性：</strong></p><ul><li>架构转型：从传统 WAR 包架构升级为现代 JAR 包架构</li><li>自定义认证：实现灵活的身份验证逻辑</li><li>安全加固：关闭 CAS 默认账号密码登录，提升系统安全性</li><li>数据库集成：集成 MyBatis 数据库访问框架</li><li>资源提取：全量提取前端静态资源和模板，方便定制</li><li>多语言支持：内置中文、英文等多语言支持</li><li>OAuth 2.0 支持：完整实现标准 OAuth 2.0 认证流程</li></ul><p><strong>版本选择：</strong></p><ul><li><a href="./cas-overlay/">CAS Overlay 文档</a> - 包含 7.3.x、6.6.x 和 5.3.x 系列的详细文档</li></ul><h3 id="智能中间件集成验证脚手架" tabindex="-1">智能中间件集成验证脚手架 <a class="header-anchor" href="#智能中间件集成验证脚手架" aria-label="Permalink to &quot;智能中间件集成验证脚手架&quot;">​</a></h3><p>智能中间件集成验证脚手架是面向开发者打造的一站式微服务项目脚手架，深度融合 AI 能力与主流中间件集成方案，支持开发者快速完成各类常用中间件服务的集成、验证与测试，大幅提升开发效率。</p><p><strong>主要特性：</strong></p><ul><li>AI接口能力：可调用Ollama本地模型和OpenAI API</li><li>多中间件集成：集成了Elasticsearch、Kafka、MongoDB、MyBatis、RabbitMQ、Redis、RocketMQ等常用中间件</li><li>统一Web界面：基于LayUI框架的直观Web界面</li><li>多数据源支持：内置多数据源配置</li><li>OAuth2.0客户端：集成OAuth2客户端认证机制</li></ul><p><strong>版本选择：</strong></p><ul><li><a href="./smart-scaffold/">智能中间件集成验证脚手架文档</a> - 包含 Spring Boot、Dubbo 和 Spring Cloud 系列的详细文档</li></ul><h2 id="技术支持" tabindex="-1">技术支持 <a class="header-anchor" href="#技术支持" aria-label="Permalink to &quot;技术支持&quot;">​</a></h2><ul><li><strong>技术支持</strong>：北京必码科技工作室</li><li><strong>官方文档</strong>：<a href="https://bima.cc" target="_blank" rel="noreferrer">https://bima.cc</a></li><li><strong>官方店铺</strong>：<a href="https://bima.taobao.com" target="_blank" rel="noreferrer">https://bima.taobao.com</a></li><li><strong>联系邮箱</strong>：<a href="mailto:bima.cc@qq.com" target="_blank" rel="noreferrer">bima.cc@qq.com</a></li><li><strong>联系微信</strong>：e18929958</li></ul><h2 id="未来规划" tabindex="-1">未来规划 <a class="header-anchor" href="#未来规划" aria-label="Permalink to &quot;未来规划&quot;">​</a></h2><p>我们计划在 dev/ 目录下添加更多开发相关的文档和项目，包括：</p><ul><li>微服务架构相关文档</li><li>容器化部署最佳实践</li><li>前端开发框架使用指南</li><li>数据库优化方案</li><li>安全最佳实践</li></ul><p>敬请期待！</p>',22)])])}const g=a(r,[["render",o]]);export{p as __pageData,g as default};
